(function(){'use strict';const API_BASE='';const API_URL=API_BASE+'/api';function initMobileMenu(){const toggle=document.querySelector('.navbar-toggle')||document.querySelector('.mobile-menu-toggle');const menu=document.querySelector('.navbar-menu')||document.querySelector('.nav-menu');if(toggle&&menu){toggle.addEventListener('click',(e)=>{e.stopPropagation();menu.classList.toggle('active');toggle.classList.toggle('active');const expanded=menu.classList.contains('active');toggle.setAttribute('aria-expanded',expanded);});document.addEventListener('click',(e)=>{if(!toggle.contains(e.target)&&!menu.contains(e.target)){menu.classList.remove('active');toggle.classList.remove('active');toggle.setAttribute('aria-expanded','false');}});menu.querySelectorAll('a').forEach(link=>{link.addEventListener('click',()=>{menu.classList.remove('active');toggle.classList.remove('active');toggle.setAttribute('aria-expanded','false');});});}}
function initSmoothScroll(){document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function(e){e.preventDefault();const target=document.querySelector(this.getAttribute('href'));if(target){target.scrollIntoView({behavior:'smooth'});}});});}
async function initCryptoTicker(){const tickerTrack=document.querySelector('.ticker-track');if(!tickerTrack)return;const cryptos=[{symbol:'BTC',name:'Bitcoin',bybit:'BTCUSDT'},{symbol:'ETH',name:'Ethereum',bybit:'ETHUSDT'},{symbol:'USDT',name:'Tether',bybit:null},{symbol:'BNB',name:'BNB',bybit:'BNBUSDT'},{symbol:'SOL',name:'Solana',bybit:'SOLUSDT'},{symbol:'XRP',name:'XRP',bybit:'XRPUSDT'},{symbol:'USDC',name:'USD Coin',bybit:null},{symbol:'ADA',name:'Cardano',bybit:'ADAUSDT'},{symbol:'AVAX',name:'Avalanche',bybit:'AVAXUSDT'},{symbol:'DOGE',name:'Dogecoin',bybit:'DOGEUSDT'},{symbol:'TRX',name:'TRON',bybit:'TRXUSDT'},{symbol:'DOT',name:'Polkadot',bybit:'DOTUSDT'},{symbol:'LINK',name:'Chainlink',bybit:'LINKUSDT'},{symbol:'MATIC',name:'Polygon',bybit:'MATICUSDT'},{symbol:'LTC',name:'Litecoin',bybit:'LTCUSDT'},{symbol:'UNI',name:'Uniswap',bybit:'UNIUSDT'},{symbol:'SHIB',name:'Shiba Inu',bybit:'SHIBUSDT'},{symbol:'ATOM',name:'Cosmos',bybit:'ATOMUSDT'},{symbol:'XLM',name:'Stellar',bybit:'XLMUSDT'},{symbol:'XMR',name:'Monero',bybit:'XMRUSDT'}];const fallbackData={'BTCUSDT':{price:84000,change:1.25},'ETHUSDT':{price:2000,change:-0.85},'BNBUSDT':{price:580,change:0.92},'SOLUSDT':{price:135,change:2.15},'XRPUSDT':{price:2.20,change:1.35},'ADAUSDT':{price:0.72,change:-0.45},'AVAXUSDT':{price:22,change:1.80},'DOGEUSDT':{price:0.18,change:3.20},'TRXUSDT':{price:0.24,change:0.50},'DOTUSDT':{price:5.20,change:-1.20},'LINKUSDT':{price:13.50,change:2.30},'MATICUSDT':{price:0.45,change:-0.80},'LTCUSDT':{price:92,change:0.60},'UNIUSDT':{price:7.80,change:1.10},'SHIBUSDT':{price:0.0000135,change:4.50},'ATOMUSDT':{price:4.80,change:-0.70},'XLMUSDT':{price:0.28,change:1.90},'XMRUSDT':{price:215,change:0.40}};let bybitMap={};try{const response=await fetch('https://api.bybit.com/v5/market/tickers?category=spot');if(response.ok){const json=await response.json();if(json.retCode===0&&json.result&&json.result.list){json.result.list.forEach(t=>{bybitMap[t.symbol]={price:parseFloat(t.lastPrice),change:parseFloat(t.price24hPcnt)*100};});}}}catch(error){}
let tickerHTML='';cryptos.forEach(crypto=>{let price,change;if(crypto.bybit===null){price=1.00;change=0.00;}else{const d=bybitMap[crypto.bybit]||fallbackData[crypto.bybit]||null;if(!d)return;price=d.price;change=d.change;}
const changeFixed=change.toFixed(2);const changeClass=change>=0?'positive':'negative';const changeSymbol=change>=0?'+':'';tickerHTML+=`<div class="ticker-item"><span class="crypto-symbol">${crypto.symbol}</span><span class="crypto-price">$${price.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:price<0.01?8:2})}</span><span class="crypto-change ${changeClass}">${changeSymbol}${changeFixed}%</span></div>`;});tickerTrack.innerHTML=tickerHTML+tickerHTML;updatePriceCards(bybitMap);}
function updatePriceCards(bybitMap){const priceMapping={'BTC':'BTCUSDT','ETH':'ETHUSDT','BNB':'BNBUSDT','SOL':'SOLUSDT'};document.querySelectorAll('.price-card').forEach(card=>{const symbolEl=card.querySelector('.price-symbol');if(!symbolEl)return;const symbol=symbolEl.textContent.trim();const bybitSymbol=priceMapping[symbol];const coinData=bybitMap[bybitSymbol];if(coinData){const priceEl=card.querySelector('.price-value');const changeEl=card.querySelector('.price-change');if(priceEl){priceEl.textContent=`$${coinData.price.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}`;}
if(changeEl){const change=coinData.change.toFixed(1);const isPositive=coinData.change>=0;changeEl.textContent=`${isPositive?'+':''}${change}%`;changeEl.className=`price-change ${isPositive?'positive':'negative'}`;}}});}
function showToast(message,type='info'){const icons={success:'✓',error:'✕',warning:'⚠',info:'ℹ'};const toast=document.createElement('div');toast.className=`toast toast-${type}`;toast.innerHTML=`<span class="toast-icon">${icons[type]||icons.info}</span><span class="toast-message">${message}</span>`;toast.style.cssText=`position:fixed;bottom:20px;right:20px;padding:1rem 1.5rem;border-radius:12px;display:flex;align-items:center;gap:10px;color:white;font-weight:500;z-index:200;transform:translateX(120%);transition:transform 0.3s ease;background:${type==='success'?'#00A86B':type==='error'?'#ef4444':type==='warning'?'#FFD700':'#3b82f6'};box-shadow:0 10px 40px rgba(0,0,0,0.3);`;document.body.appendChild(toast);setTimeout(()=>toast.style.transform='translateX(0)',10);setTimeout(()=>{toast.style.transform='translateX(120%)';setTimeout(()=>toast.remove(),300);},3000);}
function playSound(type){const sounds={success:'/assets/sounds/success.mp3',error:'/assets/sounds/error.mp3',notification:'/assets/sounds/notification.mp3'};try{const audio=new Audio(sounds[type]||sounds.notification);audio.volume=0.3;audio.play().catch(()=>{});}catch(e){}}
function formatCurrency(amount){return new Intl.NumberFormat('en-US',{style:'currency',currency:'USD'}).format(amount);}
function formatDate(dateString){return new Date(dateString).toLocaleDateString('en-US',{year:'numeric',month:'short',day:'numeric'});}
function initScrollAnimations(){const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('visible');}});},{threshold:0.1});document.querySelectorAll('.animate-on-scroll').forEach(el=>observer.observe(el));}
function initNavbarScroll(){const navbar=document.querySelector('.navbar');if(!navbar)return;window.addEventListener('scroll',()=>{if(window.scrollY>50){navbar.classList.add('scrolled');}else{navbar.classList.remove('scrolled');}});}
document.addEventListener('DOMContentLoaded',()=>{initMobileMenu();initSmoothScroll();initCryptoTicker();initScrollAnimations();initNavbarScroll();setInterval(initCryptoTicker,60000);});window.showToast=showToast;window.formatCurrency=formatCurrency;window.formatDate=formatDate;window.playSound=playSound;window.logout=function(){window.location.href='/accounts/logout/';};})();